import { Component, input, output } from '@angular/core';

@Component({
  selector: 'app-user-card',   // used as <app-user-card /> in templates
  standalone: true,            // no NgModule needed (Angular 17+ default)
  template: `
    <div class="card">
      <img [src]="user().avatar" [alt]="user().name" />
      <h2>{{ user().name }}</h2>
      <p>{{ user().role }}</p>
      <button (click)="onSelect()">Select User</button>
    </div>
  `,
  styles: [`
    .card {
      border: 1px solid #e2e8f0;
      border-radius: 12px;
      padding: 16px;
      text-align: center;
    }
  `]
})
export class UserCardComponent {
  // input() — receives data FROM the parent component
  user = input.required<{ name: string; role: string; avatar: string }>();

  // output() — emits events TO the parent component
  selected = output<string>();

  onSelect(): void {
    this.selected.emit(this.user().name);  // notify the parent
  }
}

import { Component, ChangeDetectionStrategy } from '@angular/core';
import { RouterLink } from '@angular/router';
import { ButtonComponent } from '../shared/button.component';

@Component({
  // ① The HTML tag used to insert this component
  selector: 'app-example',

  // ② Standalone = no NgModule (recommended in Angular 17+)
  standalone: true,

  // ③ Which other standalone components/directives/pipes this template uses
  imports: [RouterLink, ButtonComponent],

  // ④a Inline template (good for small components)
  template: `<h1>Hello</h1>`,

  // ④b External template file (recommended for larger components)
  // templateUrl: './example.component.html',

  // ⑤a Inline styles (array of strings)
  styles: [`h1 { color: red; }`],

  // ⑤b External stylesheet
  // styleUrl: './example.component.scss',

  // ⑥ OnPush = only re-check when inputs change or events fire (better performance)
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ExampleComponent {}

import { Component, OnInit, OnDestroy, signal } from '@angular/core';

@Component({
  selector: 'app-timer',
  standalone: true,
  template: `<p>Elapsed: {{ seconds() }}s</p>`,
})
export class TimerComponent implements OnInit, OnDestroy {
  seconds = signal(0);

  private intervalId!: ReturnType<typeof setInterval>;

  // ngOnInit — runs once after the component is created
  ngOnInit(): void {
    console.log('TimerComponent initialised');

    // Start a timer when the component appears
    this.intervalId = setInterval(() => {
      this.seconds.update(n => n + 1);
    }, 1000);
  }

  // ngOnDestroy — runs just before the component is removed from the DOM
  ngOnDestroy(): void {
    console.log('TimerComponent destroyed — cleaning up');

    // IMPORTANT: always cancel timers and subscriptions here
    clearInterval(this.intervalId);
  }
}

import { Component, input, computed } from '@angular/core';

@Component({
  selector: 'app-avatar',
  standalone: true,
  template: `
    <div [style.width.px]="size()" [style.height.px]="size()">
      <img [src]="src()" [alt]="label()" />
      <span>{{ initials() }}</span>
    </div>
  `,
})
export class AvatarComponent {
  // ① Optional input — has a default value
  size  = input<number>(40);           // default 40px

  // ② Required input — must be provided by parent
  src   = input.required<string>();    // will error at compile time if missing
  label = input.required<string>();

  // ③ computed() from inputs — auto-updates when inputs change
  initials = computed(() =>
    this.label()
      .split(' ')
      .map(w => w[0])
      .join('')
      .toUpperCase()
  );
}

// ── Usage in parent template ──────────────────────────────
// <app-avatar src="/photo.jpg" label="Ada Lovelace" [size]="64" />

import { Component, input, output } from '@angular/core';

// ── Child: ConfirmDialogComponent ────────────────────────
@Component({
  selector: 'app-confirm',
  standalone: true,
  template: `
    <div class="dialog">
      <p>{{ message() }}</p>
      <button (click)="confirm.emit(true)">Yes</button>
      <button (click)="confirm.emit(false)">Cancel</button>
    </div>
  `,
})
export class ConfirmDialogComponent {
  message = input.required<string>();

  // output<T>() — emits a value of type T to the parent
  confirm = output<boolean>();
}

// ── Parent: AppComponent ─────────────────────────────────
@Component({
  selector: 'app-root',
  standalone: true,
  imports: [ConfirmDialogComponent],
  template: `
    <app-confirm
      message="Are you sure you want to delete?"
      (confirm)="onConfirm($event)"        <!-- (output name) -->
    />
  `,
})
export class AppComponent {
  onConfirm(result: boolean): void {
    if (result) {
      console.log('User confirmed — deleting...');
    }
  }
}

import { Component, ViewChild, ElementRef, AfterViewInit } from '@angular/core';

@Component({
  selector: 'app-search-box',
  standalone: true,
  template: `
    <!-- #searchInput is a template reference variable -->
    <input #searchInput type="text" placeholder="Search..." />
    <button (click)="focusInput()">Focus</button>
  `,
})
export class SearchBoxComponent implements AfterViewInit {
  // @ViewChild reads the element with #searchInput from the template
  @ViewChild('searchInput') searchInput!: ElementRef<HTMLInputElement>;

  // Only available AFTER the view is rendered
  ngAfterViewInit(): void {
    // Auto-focus the input when the component loads
    this.searchInput.nativeElement.focus();
  }

  focusInput(): void {
    this.searchInput.nativeElement.focus();
  }
}

// ── SMART component — knows about UserService ────────────
@Component({
  selector: 'app-user-page',
  standalone: true,
  imports: [UserListComponent],
  template: `
    @if (isLoading()) {
      <p>Loading...</p>
    } @else {
      <!-- Passes data DOWN, listens to events UP -->
      <app-user-list
        [users]="users()"
        (delete)="deleteUser($event)"
      />
    }
  `,
})
export class UserPageComponent {
  private userService = inject(UserService);  // knows about services
  users     = this.userService.users;
  isLoading = this.userService.isLoading;

  deleteUser(id: string): void {
    this.userService.delete(id);
  }
}

// ── DUMB component — zero service knowledge ─────────────
@Component({
  selector: 'app-user-list',
  standalone: true,
  template: `
    @for (user of users(); track user.id) {
      <div>{{ user.name }} <button (click)="delete.emit(user.id)">Delete</button></div>
    }
  `,
})
export class UserListComponent {
  users  = input.required<User[]>();
  delete = output<string>();             // just emits, does NOT call service
}
